1	/** A live cell at coordinates (x, y). */
2	export type Cell = [number, number];
3	
4	const isSameCell = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
5	  ax === bx && ay === by;
6	
7	const areNeighbors = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
8	  Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
9	
10	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
11	  liveCells.filter(
12	    (other) => !isSameCell(cell, other) && areNeighbors(cell, other),
13	  ).length;
14	
15	const survives = (cell: Cell, liveCells: Cell[]): boolean => {
16	  const neighbors = countLiveNeighbors(cell, liveCells);
17	  return neighbors === 2 || neighbors === 3;
18	};
19	
20	/**
21	 * Computes the next generation of Conway's Game of Life
22	 * from the currently live cells.
23	 */
24	export function nextGeneration(liveCells: Cell[]): Cell[] {
25	  return liveCells.filter((cell) => survives(cell, liveCells));
26	}
27

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die from underpopulation — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("rule 2 survival: middle of row survives with 2 neighbors — [(0,0),(1,0),(2,0)] includes (1,0)", () => {
21	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
22	    expect(result).toEqual(expect.arrayContaining([[1, 0]]));
23	  });
24	  it("rule 3 overpopulation: center of plus-shape with 4 neighbors dies", () => {
25	    const plus: Cell[] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
26	    const result = nextGeneration(plus);
27	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
28	  });
29	  it.todo("rule 4 reproduction: dead cell with exactly 3 neighbors becomes alive — L-shape becomes block");
30	  it.todo("blinker oscillates vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
31	  it.todo("handles negative coordinates correctly");
32	});
